import{_ as a,o,c as r,a0 as i}from"./chunks/framework.ECMusB9M.js";const t="/plan_de_empresa/assets/mapa_de_posicionamiento_de_calidad_precio.BBAf1MzT.svg",m=JSON.parse('{"title":"2. Estrategia","description":"","frontmatter":{"layout":"default","title":"2. Estrategia"},"headers":[],"relativePath":"02_estrategia.md","filePath":"02_estrategia.md"}'),n={name:"02_estrategia.md"};function s(l,e,d,c,p,g){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_2-estrategia-de-marketing" tabindex="-1">2. Estrategia de Marketing <a class="header-anchor" href="#_2-estrategia-de-marketing" aria-label="Permalink to &quot;2. Estrategia de Marketing&quot;">​</a></h1><h2 id="_2-1-segmentacion-del-mercado" tabindex="-1">2.1. Segmentación del Mercado <a class="header-anchor" href="#_2-1-segmentacion-del-mercado" aria-label="Permalink to &quot;2.1. Segmentación del Mercado&quot;">​</a></h2><h3 id="_2-1-1-criterios-de-segmentacion" tabindex="-1">2.1.1. Criterios de segmentación <a class="header-anchor" href="#_2-1-1-criterios-de-segmentacion" aria-label="Permalink to &quot;2.1.1. Criterios de segmentación&quot;">​</a></h3><p>En este apartado veremos los criterios de segmentación:</p><ul><li>Demográficos</li><li>Geográficos</li><li>Psicográficos</li><li>Conductuales</li></ul><h2 id="_2-2-publico-objetivo-target" tabindex="-1">2.2. Público Objetivo (Target) <a class="header-anchor" href="#_2-2-publico-objetivo-target" aria-label="Permalink to &quot;2.2. Público Objetivo (Target)&quot;">​</a></h2><ul><li>Perfil de Cliente ideal / Buyer persona</li></ul><h2 id="_2-3-posicionamiento-ficha-01" tabindex="-1">2.3. Posicionamiento (FICHA 01) <a class="header-anchor" href="#_2-3-posicionamiento-ficha-01" aria-label="Permalink to &quot;2.3. Posicionamiento (FICHA 01)&quot;">​</a></h2><h3 id="justificacion" tabindex="-1">Justificación <a class="header-anchor" href="#justificacion" aria-label="Permalink to &quot;Justificación&quot;">​</a></h3><p>Queremos resolver este problema creando una aplicación que permita a los psicólogos y terapeutas gestionar y analizar los datos de sus pacientes de forma digital y a los pacientes que puedan ver sus datos en un solo lugar.</p><h3 id="calidad-del-producto-servicio" tabindex="-1">Calidad del producto/servicio <a class="header-anchor" href="#calidad-del-producto-servicio" aria-label="Permalink to &quot;Calidad del producto/servicio&quot;">​</a></h3><p>Aspiramos a una <strong>calidad alta</strong> porque el <strong>bienestar de los pacientes</strong> y la <strong>eficacia de los psicólogos</strong> son nuestra prioridad.</p><p>Más que una <em>app</em>, queremos crear un <strong>espacio digital de apoyo y confianza</strong>.</p><h4 id="materializacion-de-la-calidad" tabindex="-1">Materialización de la calidad <a class="header-anchor" href="#materializacion-de-la-calidad" aria-label="Permalink to &quot;Materialización de la calidad&quot;">​</a></h4><p>La calidad se materializa a través de:</p><ol><li><p><strong>Análisis automático de patrones</strong> Aporta <strong>inteligencia a los datos</strong>, ahorrando <em>tiempo</em> y revelando <code>insights</code>, es decir, una comprensión profunda y reveladora sobre los patrones de comportamietno del paciente.</p></li><li><p><strong>Datos en el dispositivo and exportación</strong> Ofreciendo <strong>control</strong> y <strong>privacidad</strong> al paciente mediante el almacenamiento local y la posibilidad de <code>exportar datos</code>.</p></li><li><p><strong>Diseño amigable (UX/UI)</strong> Se prioriza una <strong>interfaz intuitiva</strong> y un <strong>diseño cercano</strong> para que la herramienta sea un apoyo y no una barrera <code>fría</code> o <code>complicada</code>.</p></li><li><p><strong>Registro detallado de episodios</strong> Permite una <strong>captura de información granulada</strong> —<code>qué</code>, <code>cuándo</code>, <code>intensidad</code>, <code>antes/después</code>, <code>qué sintió</code>— resultando <strong>útil y relevante para la terapia</strong>.</p></li></ol><h3 id="precio-de-venta" tabindex="-1">Precio de venta <a class="header-anchor" href="#precio-de-venta" aria-label="Permalink to &quot;Precio de venta&quot;">​</a></h3><p>Proponemos un <strong>precio medio-alto</strong>, diferenciándonos de las <em>aplicaciones de bajo coste</em>. Fijando dicho precio según la <strong>estrategia del mapa de posicionamiento</strong>, ocuparíamos un <strong>nicho de mercado</strong>, evitando dos extremos claramente definidos:</p><ol><li>El cuadrante de <strong>precio bajo</strong>, ocupado por <em>apps genéricas</em> de <strong>calidad baja–media</strong>.</li><li>El cuadrante de <strong>precio alto</strong>, ocupado por <em>softwares complejos de gestión clínica</em> que, a menudo, carecen de un <strong>diseño amigable</strong> para el <em>paciente</em>.</li></ol><h4 id="enfoque-del-modelo-de-negocio" tabindex="-1">Enfoque del modelo de negocio <a class="header-anchor" href="#enfoque-del-modelo-de-negocio" aria-label="Permalink to &quot;Enfoque del modelo de negocio&quot;">​</a></h4><p>Dado que la aplicación nace para servir como solución a una <strong>asociación (SEMBREM)</strong>, nuestro modelo de negocio debe ser <code>sostenible</code> y estar <strong>centrado en el cliente profesional</strong>. Por ello, no competimos por ser la opción <em>más barata</em>, sino por ofrecer el mejor <strong><code>valor percibido</code></strong>.</p><h4 id="justificacion-del-precio" tabindex="-1">Justificación del precio <a class="header-anchor" href="#justificacion-del-precio" aria-label="Permalink to &quot;Justificación del precio&quot;">​</a></h4><p>Justificamos el <strong>precio medio-alto</strong> con el claro <strong>retorno de la inversión (<code>ROI</code>)</strong> que obtienen nuestros clientes, materializado en:</p><ol><li><strong>Ahorro de tiempo</strong></li><li><strong>Mayor eficacia terapéutica</strong></li></ol><h3 id="competencia-y-soluciones-existentes" tabindex="-1">Competencia y soluciones existentes <a class="header-anchor" href="#competencia-y-soluciones-existentes" aria-label="Permalink to &quot;Competencia y soluciones existentes&quot;">​</a></h3><p>En el mercado actual del <strong>bienestar digital</strong> y la <strong>psicología</strong> existen varias soluciones que cubren <em>partes del problema</em>, pero <strong>no lo abordan de forma completa</strong> como nuestra propuesta.</p><p>Podemos agruparlas en <strong>tres grandes bloques</strong>:</p><h4 id="software-de-gestion-clinica" tabindex="-1"><strong>Software de gestión clínica</strong> <a class="header-anchor" href="#software-de-gestion-clinica" aria-label="Permalink to &quot;**Software de gestión clínica**&quot;">​</a></h4><ol><li><p><strong>Ejemplos</strong></p><ul><li><a href="https://www.eholo.health/" target="_blank" rel="noreferrer">Eholo</a></li><li><a href="https://dricloud.com/?srsltid=AfmBOoo-pd5dpdryDid_H5ZgJo17lKFXyJTI8MlViJIF87XlWNx03djT" target="_blank" rel="noreferrer">DriCloud</a></li><li><a href="https://gestionsaludmental.com/" target="_blank" rel="noreferrer">Eudatox</a></li><li><a href="https://www.moodo.ai/" target="_blank" rel="noreferrer">moodo</a></li></ul></li><li><p><strong>Análisis</strong> Son herramientas muy potentes para <strong>facturar</strong> y <strong>gestionar la consulta</strong>. Sin embargo, la parte de <code>autorregistro</code> resulta <strong>muy fría</strong>, ya que el <em>paciente</em> siente que está rellenando un <code>formulario médico aburrido</code>, lo que provoca que deje de utilizarlo.</p></li><li><p><strong>Nuestra solución</strong> No queremos que el paciente <em>“rellene datos”</em>, sino que lo haga sintiendo que utiliza un <strong>diario de bienestar</strong> <em>amigable</em> y cercano.</p></li></ol><h4 id="aplicaciones-de-consumo" tabindex="-1">Aplicaciones de consumo <a class="header-anchor" href="#aplicaciones-de-consumo" aria-label="Permalink to &quot;Aplicaciones de consumo&quot;">​</a></h4><ol><li><p><strong>Ejemplos</strong></p><ul><li><a href="https://daylio.net/" target="_blank" rel="noreferrer">Daylio</a></li><li><a href="https://play.google.com/store/apps/details?id=com.bluesignum.bluediary&amp;hl=es" target="_blank" rel="noreferrer">DailyBean</a></li><li><a href="https://www.yana.ai/es/home" target="_blank" rel="noreferrer">Yana</a></li></ul></li><li><p><strong>Análisis</strong> Destacan por un <strong>diseño excelente</strong> y una <strong>gran facilidad de uso</strong>. El principal problema es que el <em>psicólogo</em> de la organización <strong>no recibe esos datos</strong>. La información se queda en el <code>móvil del usuario</code> o en una <code>nube privada</code>, perdiendo <strong>valor terapéutico</strong> para la sesión y la comunicación entre <em>paciente</em> y <em>profesional</em>. Además, muchas de las apps internacionales no garantizan el cumplimiento del RGPD sanitario español.</p></li><li><p><strong>Nuestra solución</strong> Queremos ser el <strong>puente de conexión</strong> entre ambas entidades:</p><ul><li>Tomamos lo mejor del <strong>diseño</strong> de la competencia.</li><li>Permitir que el paciente sea dueño de sus propios datos en su móvil, pero esta decida compartirlos de forma cifrada con su terapeuta de SEMBREM.</li><li>Conectamos los <strong>datos</strong> con el <em>terapeuta</em> o <em>psicólogo de Alzira (SEMBRE)</em> de forma <code>segura</code>.</li></ul></li></ol><h4 id="el-autorregistro-clasico" tabindex="-1">El autorregistro clásico <a class="header-anchor" href="#el-autorregistro-clasico" aria-label="Permalink to &quot;El autorregistro clásico&quot;">​</a></h4><ol><li><p><strong>Ejemplos</strong> Papel y boli.</p></li><li><p><strong>Análisis</strong> Es una herramienta <strong>útil</strong>, pero los datos pueden perderse con el <code>tiempo</code> y no permite generar <code>gráficos automáticos</code> ni análisis avanzados. Además, el papel no permite el <strong>registo en tiempo real</strong>.</p></li><li><p><strong>Nuestra solución</strong> Ofrecemos <strong>análisis automático de patrones</strong> mediante <code>gráficos</code>, junto con una <strong>interfaz moderna</strong> que el soporte tradicional no puede proporcionar. Mientras que el paciente suele rellenar el papel antes de entrar a la consulta, la app permite registrar el episodio justo cuanto ocurre.</p></li></ol><h3 id="_2-3-1-propuesta-de-valor" tabindex="-1">2.3.1. Propuesta de valor <a class="header-anchor" href="#_2-3-1-propuesta-de-valor" aria-label="Permalink to &quot;2.3.1. Propuesta de valor&quot;">​</a></h3><p>Es importante recordar que <strong>no es lo mismo calidad que <code>calidad percibida</code></strong>, ya que esta última depende en gran medida del <strong>marketing</strong> y de la <strong>experiencia del usuario</strong>.</p><p>Queremos que el <strong>valor percibido</strong> vaya más allá del <em>software</em> y se base en una forma de <strong>acompañamiento terapéutico</strong> más cercano y <em>empático</em>, incluso dentro del entorno digital.</p><h4 id="objetivo-de-percepcion-del-producto" tabindex="-1">Objetivo de percepción del producto <a class="header-anchor" href="#objetivo-de-percepcion-del-producto" aria-label="Permalink to &quot;Objetivo de percepción del producto&quot;">​</a></h4><p>Por esta razón, nuestro objetivo es que la aplicación sea percibida de la siguiente manera:</p><ol><li><p><strong>Para el paciente</strong> Como un <strong>compañero de viaje</strong> <em>discreto</em>, <em>cercano</em> y <code>sin juicios</code>. Un <strong>espacio de confianza</strong> donde puede ser totalmente honesto, que le ayude a:</p><ul><li>Poner nombre a lo que siente</li><li>Entender su propio proceso</li></ul><p>Es una herramienta que <strong>le da poder y voz</strong> dentro de su proceso terapéutico.</p></li><li><p><strong>Para el psicólogo</strong> Como un <strong>aliado estratégico</strong> que potencia su <em>intuición</em>. No es una máquina para <code>reemplazar</code> su trabajo, sino una <strong>lente de aumento</strong> que:</p><ul><li>Aporta <strong>claridad</strong> sobre los datos del día a día del paciente</li><li>Reduce la <strong>carga de gestión de información</strong></li><li>Permite dedicar más tiempo a la <strong>conexión humana</strong></li></ul></li></ol><h4 id="valor-percibido-global" tabindex="-1">Valor percibido global <a class="header-anchor" href="#valor-percibido-global" aria-label="Permalink to &quot;Valor percibido global&quot;">​</a></h4><p>Por todo esto, el <strong>valor percibido</strong> de la aplicación es el de ser un <strong>puente de confianza y entendimiento</strong> entre el <em>paciente</em> y el <em>profesional</em>, bajo un <strong>modelo SaaS (Software as a Service)</strong> que garantiza la actualización y el soporte continuo.</p><h3 id="_2-3-2-mapa-de-posicionamiento" tabindex="-1">2.3.2. Mapa de posicionamiento <a class="header-anchor" href="#_2-3-2-mapa-de-posicionamiento" aria-label="Permalink to &quot;2.3.2. Mapa de posicionamiento&quot;">​</a></h3><p><img src="'+t+'" alt="mapa_de_posicionamiento_de_calidad_precio"></p><h2 id="_2-4-estrategia-general" tabindex="-1">2.4. Estrategia General <a class="header-anchor" href="#_2-4-estrategia-general" aria-label="Permalink to &quot;2.4. Estrategia General&quot;">​</a></h2><p>!!! Tip - Estrategia de crecimiento (Ansoff): <a href="https://www.esic.edu/rethink/marketing-y-comunicacion/que-es-la-matriz-de-ansoff-para-que-sirve-ejemplos-c" target="_blank" rel="noreferrer">Matriz de Ansoff - ESIC</a> - Estrategia competitiva (liderazgo en costes, diferenciación, enfoque): <a href="https://www.obsbusiness.school/blog/estrategia-competitive-definicion-tipos-y-planteamiento" target="_blank" rel="noreferrer">Estrategia competitiva - OBS</a> - Estrategia de marca (si aplica): <a href="https://advertising.amazon.com/es-es/library/guides/brand-strategy" target="_blank" rel="noreferrer">Brand Strategy - Amazon Advertising</a></p>',45)])])}const h=a(n,[["render",s]]);export{m as __pageData,h as default};
